  // Levenshtein con corte
  private int editDistanceUpTo2(String a, String b) {
    if (a == null || b == null) return 99;
    a = a.trim();
    b = b.trim();
    int n = a.length(), m = b.length();
    if (Math.abs(n - m) > 2) return 99;

    int[] prev = new int[m + 1];
    int[] cur  = new int[m + 1];
    for (int j = 0; j <= m; j++) prev[j] = j;

    for (int i = 1; i <= n; i++) {
      cur[0] = i;
      int bestRow = cur[0];

      char ca = a.charAt(i - 1);
      for (int j = 1; j <= m; j++) {
        int cost = (ca == b.charAt(j - 1)) ? 0 : 1;
        int del  = prev[j] + 1;
        int ins  = cur[j - 1] + 1;
        int sub  = prev[j - 1] + cost;
        int v = Math.min(Math.min(del, ins), sub);
        cur[j] = v;
        if (v < bestRow) bestRow = v;
      }

      if (bestRow > 2) return 99;
      int[] tmp = prev; prev = cur; cur = tmp;
    }
    return prev[m];
  }

  private String nearestKeyword(String s) {
    String best = null;
    int bestD = 99;

    for (String kw : KEYWORDS) {
      int d = editDistanceUpTo2(s, kw);

      if (d < bestD) {
        bestD = d;
        best = kw;
        continue;
      }

      // DESEMPATE: si tienen la misma distancia, decide mejor
      if (d == bestD && best != null) {
        char s0 = (s != null && !s.isEmpty()) ? s.charAt(0) : 0;
        boolean kwSame0   = (!kw.isEmpty()   && kw.charAt(0)   == s0);
        boolean bestSame0 = (!best.isEmpty() && best.charAt(0) == s0);

        // Preferir keyword que empiece igual que el typo
        if (kwSame0 && !bestSame0) {
          best = kw;
        }
        // Si ambos o ninguno empiezan igual, preferir la más larga (ej: def > if)
        else if (kwSame0 == bestSame0) {
          if (kw.length() > best.length()) best = kw;
        }
      }
    }

    return (bestD <= 2) ? best : null;
  }

