  /* ==== INICIO: CONTADORES DE CONTEXTO (ciclos y funciones) ==== */
  /* loopDepth:
     - Se incrementa al entrar a un for/while
     - Se decrementa al salir
     - Sirve para validar break/continuar
  */
  private int loopDepth = 0;  // >0 significa que estamos dentro de un for/while
  /* funcDepth:
     - Se incrementa al entrar a una función
     - Se decrementa al salir
     - Sirve para validar return
  */
  private int funcDepth = 0;  // >0 significa que estamos dentro de una función

  /* ===== Helpers: ciclo ===== */
  private void enterLoop() { loopDepth++; }
  private void exitLoop()  { if (loopDepth > 0) loopDepth--; }
  private boolean inLoop() { return loopDepth > 0; }

  /* ===== Helpers: función ===== */
  private void enterFunc() { funcDepth++; }
  private void exitFunc()  { if (funcDepth > 0) funcDepth--; }
  private boolean inFunc() { return funcDepth > 0; }
  /* ==== FIN: CONTADORES DE CONTEXTO (ciclos y funciones) ==== */

  /* ==== INICIO: BLOQUEO DE “AUTO-INICIALIZACIÓN” ==== */
  private final java.util.HashSet<String> initializing = new java.util.HashSet<>();

  /* ===== Marcar inicio de inicialización ===== */
  private void beginInit(Token id) { initializing.add(id.image); }
  /* ===== Marcar fin de inicialización ===== */
  private void endInit(Token id)   { initializing.remove(id.image); }
  /* ===== Está en inicialización ===== */
  private boolean isInitializing(Token id) { return initializing.contains(id.image); }
  /* ==== FIN: BLOQUEO DE “AUTO-INICIALIZACIÓN” ==== */

  /* ==== INICIO: VALIDACIÓN DE PARÁMETROS DUPLICADOS ==== */
  private void validateNoDuplicateParams(java.util.ArrayList<Token> params, Token funcName) {
    java.util.HashSet<String> seen = new java.util.HashSet<>();
    for (Token p : params) {
      String name = p.image;
      if (seen.contains(name)) {
        semanticError(p, "Par\u00e1metro duplicado '" + name + "' en la funci\u00f3n '" + funcName.image + "'.");
      } else {
        seen.add(name);
      }
    }
  }
  /* ==== FIN: VALIDACIÓN DE PARÁMETROS DUPLICADOS ==== */




  /* ========== INICIO: CAPTURA DE EXPRESIONES EN INFIJA ============= */

  private java.util.ArrayList<String> currentInfix = null;
  private int exprCaptureDepth = 0;

  private final java.util.ArrayList<String> postfixReports = new java.util.ArrayList<>();

  private void beginExprCapture() {
    if (exprCaptureDepth == 0) {
      currentInfix = new java.util.ArrayList<>();
    }
    exprCaptureDepth++;
  }

  private java.util.ArrayList<String> endExprCapture() {
    if (exprCaptureDepth <= 0) return null;

    exprCaptureDepth--;
    if (exprCaptureDepth == 0) {
      java.util.ArrayList<String> out = new java.util.ArrayList<>(currentInfix);
      currentInfix = null;
      return out;
    }
    return null;
  }

  private boolean isCapturingExpr() {
    return exprCaptureDepth > 0 && currentInfix != null;
  }

  private void cap(String lexeme) {
    if (isCapturingExpr() && lexeme != null) {
      currentInfix.add(lexeme);
    }
  }

  private void savePostfixReport(String context, java.util.List<String> infix, java.util.List<String> postfix) {
    if (infix == null || postfix == null) return;

    postfixReports.add(
      context +
      "\n  infija:   " + String.join(" ", infix) +
      "\n  postfija: " + String.join(" ", postfix)
    );
  }

  public void printPostfixReports() {
    if (postfixReports.isEmpty()) {
      System.out.println("No se gener\u00f3 postfija.");
      return;
    }

    System.out.println("=============== POSTFIJA GENERADA ===============");
    for (String s : postfixReports) {
      System.out.println(s);
    }
  }

  /* ========== FIN: CAPTURA DE EXPRESIONES EN INFIJA ============= */


