  void SafeStatement() throws ParseException {inSafeStatement = true;
  stmtHadSyntaxError = false;
  typoKeywords.clear();

  // Léxico: INVALID
  if (getToken(1).kind == INVALID) {
    Token bad = getNextToken();
    lexicalError(bad);
    inSafeStatement = false;
    return;
  }

  try {
    Statement();
  } catch (ParseException e) {
    stmtHadSyntaxError = true;
    syntacticError(e);
    panicRecover();
  } finally {
    inSafeStatement = false;
  }
  }

  void KeywordTypo() throws ParseException {Token t = getToken(1);
  if (t == null || t.kind != IDENT) return;

  String sug = nearestKeyword(t.image);
  if (sug != null) {
    typoKeywords.add(t.image);
    keywordTypoError(t, sug);
  }
  }

